// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract FundManagement is ReentrancyGuard {
    address public owner;
    mapping(address => address) public pools; // poolAddress => rewardTokenAddress

    event PoolAdded(address indexed pool, address indexed rewardToken);
    event PoolRemoved(address indexed pool);
    event FundTransferred(address indexed pool, address indexed receiver, uint256 amount);
    event FundRescued(uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier onlyPool() {
        require(pools[msg.sender] != address(0), "Not a valid pool");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function addPool(address _pool, address _rewardToken) external onlyOwner nonReentrant {
        require(_pool != address(0), "Invalid pool address");
        require(_rewardToken != address(0), "Invalid reward token address");
        require(pools[_pool] == address(0), "Pool already exists");

        pools[_pool] = _rewardToken;
        emit PoolAdded(_pool, _rewardToken);
    }

    function removePool(address _pool) external onlyOwner nonReentrant {
        require(pools[_pool] != address(0), "Pool does not exist");

        delete pools[_pool];
        emit PoolRemoved(_pool);
    }

    function transferTo(address _receiver, uint256 _amount) external onlyPool nonReentrant {
        require(_receiver != address(0), "Invalid receiver address");
        require(_amount > 0, "Amount must be greater than zero");

        (bool sent, ) = _receiver.call{value: _amount}("");
        require(sent, "Failed to send Ether");

        emit FundTransferred(msg.sender, _receiver, _amount);
    }

    function rescueFund() external onlyOwner nonReentrant {
        uint256 balance = address(this).balance;
        require(balance > 0, "No funds to rescue");

        (bool sent, ) = owner.call{value: balance}("");
        require(sent, "Failed to send Ether");

        emit FundRescued(balance);
    }
}
```

